const baseUrl = 'https://meetguru.payform.ru/?do=link&sys=meetguru'

// Получаем список курсов
const shop = formulas['82834519-0612-4d5a-b296-39d2223de9bf']()?.data ?? []

// Уникальный order_id — можешь заменить на user_id + timestamp
const total = Number(collections['438a40f5-d2c5-4743-bd4f-616a13bb3016']?.total) ?? 0
const orderId = `${total + 1}`

// Куда редиректить после оплаты
const urlSuccess = 'https://vk.com/'

// Проверка, что shop — массив
if (!Array.isArray(shop) || shop.length === 0) return baseUrl

// Сборка параметров продуктов
const productParams = shop.map((item, index) =>
  `products[${index}][price]=${encodeURIComponent(item.price)}&` +
  `products[${index}][quantity]=${encodeURIComponent(item.quantity)}&` +
  `products[${index}][name]=${encodeURIComponent(item.course_name)}`
).join('&')

// Финальная ссылка
return `${baseUrl}&order_id=${encodeURIComponent(orderId)}&${productParams}&urlSuccess=${encodeURIComponent(urlSuccess)}`
